import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

function HomePage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('http://localhost:8000/api/videos/')
      .then(response => {
        setVideos(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки видео:', error);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return <div style={{ color: 'white', textAlign: 'center', marginTop: 50 }}>Загрузка...</div>;
  }

  return (
    <div>
      <div style={{ textAlign: 'center', margin: '40px 0' }}>
        <h1 style={{ color: 'white', fontSize: 48, marginBottom: 10 }}>Видеоплатформа</h1>
        <p style={{ color: '#aaa', fontSize: 18 }}>Смотрите, загружайте и делитесь видео</p>
      </div>
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', 
        gap: 24 
      }}>
        {videos.map(video => (
          <Link to={`/video/${video.id}`} key={video.id} style={{ textDecoration: 'none' }}>
            <div style={{ cursor: 'pointer' }}>
              <div style={{ 
                backgroundColor: '#272727', 
                borderRadius: 12, 
                overflow: 'hidden',
                transition: 'transform 0.2s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.02)'}
              onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}>
                
                {/* Показываем сгенерированное превью */}
                {video.thumbnail_url ? (
                  <img 
                    src={`http://localhost:8000${video.thumbnail_url}`} 
                    alt={video.title}
                    style={{ width: '100%', aspectRatio: '16/9', objectFit: 'cover' }}
                  />
                ) : (
                  <div style={{ 
                    width: '100%', 
                    aspectRatio: '16/9', 
                    backgroundColor: '#1a1a1a', 
                    display: 'flex', 
                    alignItems: 'center', 
                    justifyContent: 'center', 
                    color: '#666' 
                  }}>
                    🎬 Загрузка...
                  </div>
                )}
                
                <div style={{ padding: 12 }}>
                  <h3 style={{ color: 'white', fontSize: 16, marginBottom: 4 }}>{video.title}</h3>
                  <p style={{ color: '#aaa', fontSize: 14 }}>{video.uploaded_by_name || 'Аноним'}</p>
                  <p style={{ color: '#888', fontSize: 12 }}>{video.views || 0} просмотров</p>
                </div>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </div>
  );
}

export default HomePage;
